section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/growth-experiment-design.json",
  "title": "Growth Experiment Design output",
  "type": "object",
  "required": [
    "slug",
    "owner",
    "review_deadline",
    "summary",
    "sections",
    "deviation_log_reference"
  ],
  "properties": {
    "slug": {
      "type": "string",
      "const": "growth-experiment-design"
    },
    "owner": {
      "type": "string",
      "minLength": 1
    },
    "review_deadline": {
      "type": "string",
      "format": "date"
    },
    "summary": {
      "type": "string",
      "minLength": 20,
      "maxLength": 400
    },
    "sections": {
      "type": "array",
      "minItems": 3,
      "items": {
        "type": "object",
        "required": [
          "name",
          "content"
        ],
        "properties": {
          "name": {
            "type": "string"
          },
          "content": {
            "type": "string",
            "minLength": 10
          }
        },
        "additionalProperties": false
      }
    },
    "deviation_log_reference": {
      "type": "string",
      "minLength": 1
    },
    "signoff": {
      "type": "object",
      "required": [
        "reviewer",
        "date"
      ],
      "properties": {
        "reviewer": {
          "type": "string"
        },
        "date": {
          "type": "string",
          "format": "date"
        }
      },
      "additionalProperties": false
    }
  },
  "additionalProperties": false
}

example.code:
{
  "slug": "growth-experiment-design",
  "owner": "growth lead",
  "review_deadline": "2026-06-15",
  "summary": "Spec for Growth Experiment Design covering preconditions, procedure, output, and review gate.",
  "sections": [
    {
      "name": "preconditions",
      "content": "All Applies If items confirmed in writing."
    },
    {
      "name": "procedure",
      "content": "Steps 1..n executed per content/04-procedure.xml."
    },
    {
      "name": "review",
      "content": "Human reviewer signed off on date."
    }
  ],
  "deviation_log_reference": "ops/deviation-log.md#L42",
  "signoff": {
    "reviewer": "growth lead",
    "date": "2026-06-10"
  }
}
